   657|function buildProviderReadiness(rows: OwnerVariableRow[]): Record<OwnerVariableProvider, ProviderReadiness> {
   658|  const rowByName = new Map(rows.map((row) => [row.name, row]));
   659|  const providers = Array.from(new Set(OWNER_VARIABLES.map((item) => item.provider))) as OwnerVariableProvider[];
   660|  return Object.fromEntries(providers.map((provider) => {
   661|    const required = OWNER_VARIABLES.filter((item) => item.provider === provider && item.required).map((item) => item.name);
   662|    // A required variable is satisfied if it's in the encrypted store OR in the backend runtime env.
   663|    const saved = required.filter((name) => rowByName.has(name) || readEnv(name));
   664|    const missing = required.filter((name) => !rowByName.has(name) && !readEnv(name));
   665|    const providerRows = OWNER_VARIABLES.filter((item) => item.provider === provider).map((item) => rowByName.get(item.name)).filter((row): row is OwnerVariableRow => Boolean(row));
   666|    const hasInvalid = providerRows.some((row) => row.status === 'invalid');
   667|    const hasTested = required.length > 0 && required.every((name) => rowByName.get(name)?.status === 'tested');
   668|    const lastTestedAt = providerRows
   669|      .map((row) => row.last_tested_at)
   670|      .filter((value): value is string => Boolean(value))
   671|      .sort()
   672|      .at(-1) ?? null;
   673|    const status: ProviderReadiness['status'] = missing.length > 0 ? 'missing' : hasInvalid ? 'invalid' : hasTested ? 'tested' : 'saved';
   674|    return [provider, {
   675|      provider,
   676|      status,
   677|      requiredVariableNames: required,
   678|      savedVariableNames: saved,
   679|      missingVariableNames: missing,
   680|      lastTestedAt,
   681|      secretValuesReturned: false as const,
   682|    }];
   683|  })) as Record<OwnerVariableProvider, ProviderReadiness>;
